class GrpcChannelPool:
    """Manages gRPC channel connections to backend services."""

    def __init__(self):
        self._channels: Dict[str, grpc.Channel] = {}
        self._options = [
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
        ]

    def get_channel(self, service: BackendService) -> grpc.Channel:
        """Get or create a gRPC channel for a backend service."""
        if service.address not in self._channels:
            if service.use_tls:
                credentials = grpc.ssl_channel_credentials()
                channel = grpc.secure_channel(
                    service.address, credentials, options=self._options
                )
            else:
                channel = grpc.insecure_channel(
                    service.address, options=self._options
                )
            self._channels[service.address] = channel

        return self._channels[service.address]

    def close_all(self):
        """Close all channels."""
        for channel in self._channels.values():
            channel.close()
        self._channels.clear()


